mapper.select:
SELECT COUNT(*) FROM analysis_task

    status = 'COMPLETED'
    AND user_id = #{userId}

SELECT vc.sentiment_label, COUNT(*) as count FROM video_comment vc INNER JOIN analysis_task at ON vc.task_id = at.task_id
at.user_id = #{userId}
GROUP BY vc.sentiment_label

SELECT DATE(created_at) as date, COUNT(*) as count FROM analysis_task
created_at >= DATE_SUB(CURDATE(), INTERVAL 7 DAY) AND user_id = #{userId}
GROUP BY DATE(created_at) ORDER BY date ASC
